using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class PredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class EvaluationResponse
{
    public float MacroAccuracy { get; set; }
    public float MicroAccuracy { get; set; }
    public float LogLoss { get; set; }
    public float LogLossReduction { get; set; }
    public List<CategoryMetric> PerCategoryMetrics { get; set; } = [];
}

public class CategoryMetric
{
    public string Category { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private ITransformer? _model;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private string[]? _categoryNames;

    public bool IsModelTrained => _model is not null;

    public TicketClassifierService()
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        _modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
    }

    public void TrainModel()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Combine text features and normalize priority
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(data);

        // Cache category names from the label column for confidence mapping
        var labelColumn = data.Schema["Category"];
        var categories = data.GetColumn<string>(labelColumn).Distinct().OrderBy(c => c).ToArray();
        _categoryNames = categories;

        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);
        _mlContext.Model.Save(_model, data.Schema, _modelPath);
    }

    public EvaluationResponse Evaluate()
    {
        if (_model is null)
            throw new InvalidOperationException("Model has not been trained yet.");

        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Re-apply label key mapping so we can evaluate
        var predictions = _model.Transform(data);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        var response = new EvaluationResponse
        {
            MacroAccuracy = (float)metrics.MacroAccuracy,
            MicroAccuracy = (float)metrics.MicroAccuracy,
            LogLoss = (float)metrics.LogLoss,
            LogLossReduction = (float)metrics.LogLossReduction,
        };

        // Per-class metrics from the confusion matrix
        for (int i = 0; i < metrics.PerClassLogLoss.Count; i++)
        {
            var cm = metrics.ConfusionMatrix;
            double tp = cm.Counts[i][i];
            double rowSum = cm.Counts[i].Sum();   // actual positives
            double colSum = cm.Counts.Select(row => row[i]).Sum(); // predicted positives

            double precision = colSum > 0 ? tp / colSum : 0;
            double recall = rowSum > 0 ? tp / rowSum : 0;
            double f1 = (precision + recall) > 0
                ? 2 * precision * recall / (precision + recall) : 0;

            response.PerCategoryMetrics.Add(new CategoryMetric
            {
                Category = cm.ClassNames[i],
                Precision = Math.Round(precision, 4),
                Recall = Math.Round(recall, 4),
                F1Score = Math.Round(f1, 4),
            });
        }

        return response;
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        if (_predictionEngine is null || _categoryNames is null)
            throw new InvalidOperationException("Model has not been trained yet.");

        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionEngine.Predict(ticketData);

        // Map scores to category names using the label key ordering
        var labelKeyColumn = _model!.GetOutputSchema(
            SchemaDefinition.Create(typeof(TicketData)))["Label"];
        var keyType = labelKeyColumn.Type as KeyDataViewType;
        VBuffer<ReadOnlyMemory<char>> labelValues = default;
        labelKeyColumn.GetKeyValues(ref labelValues);
        var labels = labelValues.DenseValues().Select(v => v.ToString()).ToArray();

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < labels.Length; i++)
        {
            confidence[labels[i]] = i < prediction.Score.Length
                ? MathF.Round(prediction.Score[i], 4) : 0f;
        }

        return new PredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence,
        };
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>
    /// Trains the ML model using the CSV training data.
    /// </summary>
    [HttpPost("train")]
    public IActionResult Train()
    {
        _classifier.TrainModel();
        return Ok(new { message = "Model trained successfully." });
    }

    /// <summary>
    /// Returns evaluation metrics for the trained model.
    /// </summary>
    [HttpGet("evaluate")]
    public ActionResult<EvaluationResponse> Evaluate()
    {
        if (!_classifier.IsModelTrained)
            return BadRequest(new { error = "Model has not been trained. POST /api/tickets/train first." });

        var metrics = _classifier.Evaluate();
        return Ok(metrics);
    }

    /// <summary>
    /// Predicts the category for a support ticket.
    /// </summary>
    [HttpPost("predict")]
    public ActionResult<PredictionResponse> Predict([FromBody] TicketRequest request)
    {
        if (!_classifier.IsModelTrained)
            return BadRequest(new { error = "Model has not been trained. POST /api/tickets/train first." });

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest(new { error = "Priority must be between 1 and 3." });

        var prediction = _classifier.Predict(request);
        return Ok(prediction);
    }
}

